import React, { useEffect, useState } from "react";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";
import API from "../api";

function ReportsPage() {
  const [reports, setReports] = useState([]);
  const [search, setSearch] = useState("");

  useEffect(() => {
    fetchReports();
  }, []);

  const fetchReports = async (query = "") => {
    try {
      const res = await API.get(`/reports?search=${query}`);
      setReports(res.data);
    } catch (error) {
      console.error("Failed to fetch reports");
    }
  };

  const handleSearch = (e) => {
    const value = e.target.value;
    setSearch(value);
    fetchReports(value);
  };

  const deleteReport = async (id) => {
    if (!window.confirm("Delete this report?")) return;
    try {
      await API.delete(`/reports/${id}`);
      fetchReports(search);
    } catch (error) {
      alert("Delete failed");
    }
  };

  const exportExcel = () => {
    window.open("http://127.0.0.1:5000/export-excel", "_blank");
  };

  const downloadPDF = (id) => {
    window.open(`http://127.0.0.1:5000/generate-pdf/${id}`, "_blank");
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role="admin" />

      <div className="main-content">
        <Navbar
          title="Reports Management"
          subtitle="Search, download, export and manage patient AI reports"
        />

        <div className="dashboard-card mb-4">
          <div className="d-flex justify-content-between align-items-center flex-wrap gap-3">
            <input
              type="text"
              className="form-control search-box"
              placeholder="Search by patient or doctor..."
              value={search}
              onChange={handleSearch}
              style={{ maxWidth: "350px" }}
            />

            <button className="btn btn-premium" onClick={exportExcel}>
              Export Excel
            </button>
          </div>
        </div>

        <div className="table-premium">
          <table className="table table-hover align-middle">
            <thead>
              <tr>
                <th>#</th>
                <th>Patient</th>
                <th>Predicted Disease</th>
                <th>Doctor</th>
                <th>Specialization</th>
                <th>Confidence</th>
                <th>Date</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {reports.length > 0 ? (
                reports.map((report, index) => (
                  <tr key={report.id}>
                    <td>{index + 1}</td>
                    <td>{report.patient_name}</td>
                    <td>{report.predicted_disease}</td>
                    <td>{report.predicted_doctor}</td>
                    <td>{report.specialization}</td>
                    <td>{report.confidence}%</td>
                    <td>{report.created_at}</td>
                    <td>
                      <button
                        className="action-btn btn-view"
                        onClick={() => downloadPDF(report.id)}
                      >
                        PDF
                      </button>
                      <button
                        className="action-btn btn-delete"
                        onClick={() => deleteReport(report.id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="8" className="text-center py-4">
                    No reports found
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default ReportsPage;
